components.css:
.post {
    .l-about {
        width: 100%;
    }

    .c-content-about-ecosystem-3col-01 {
        display: flex;
        flex-direction: column;
        gap: var(--px40);
        padding: var(--px80) var(--px60);
        background-color: var(--color-secondary-tint);
    }

    .c-content-about-ecosystem-3col-01 h2,
    .c-content-about-ecosystem-3col-01 p,
    .c-content-about-ecosystem-3col-01 figure {
        margin: 0;
        padding: 0;
    }

    .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__head {
        display: flex;
        flex-direction: column;
        gap: 12px;
    }

    .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__eyebrow {
        color: var(--color-primary);
        font-size: var(--px14);
        font-weight: 700;
        letter-spacing: 0.12em;
        line-height: 1.4;
        text-transform: uppercase;
    }

    .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__title {
        color: var(--color-primary-shade);
        font-family: var(--font-family02);
        font-size: var(--px80);
        font-weight: 700;
        line-height: 0.95;
text-align: left;
    }

    .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__body {
        display: flex;
        flex-direction: column;
        gap: var(--px30);
    }

    .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__grid-top {
        display: grid;
        grid-template-columns: minmax(0, 1.05fr) minmax(0, 0.95fr) minmax(0, 1fr);
        gap: var(--px24);
    }

    .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__grid-bottom {
        display: grid;
        grid-template-columns: minmax(0, 1.65fr) minmax(0, 0.75fr);
        gap: var(--px24);
    }

    .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__col-text {
        display: flex;
        flex-direction: column;
        gap: var(--px20);
    }

    .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__col-media-a {
        padding-top: var(--px20);
    }

    .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__col-note {
        display: flex;
        align-items: center;
        padding-top: var(--px20);
    }

    .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__text,
    .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__text-note {
        color: var(--color-primary);
        font-size: var(--px16);
        line-height: 1.9;
    }

    .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__media-a,
    .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__media-b,
    .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__media-c {
        overflow: hidden;
        background-color: var(--color-background);
    }

    .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__media-a {
        aspect-ratio: 4 / 5;
    }

    .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__media-b {
        aspect-ratio: 3 / 4;
    }

    .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__media-c {
        aspect-ratio: 16 / 9;
    }

    .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__image-a,
    .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__image-b,
    .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__image-c {
        display: block;
        width: 100% !important;
        height: 100% !important;
        max-width: none !important;
        max-height: none !important;
        object-fit: cover;
    }

    .c-content-about-ecosystem-3col-01.c-content-about-ecosystem-3col-01--compact .c-content-about-ecosystem-3col-01__title {
        font-size: var(--px60);
    }

    .c-content-about-ecosystem-3col-01.c-content-about-ecosystem-3col-01--text-large .c-content-about-ecosystem-3col-01__text,
    .c-content-about-ecosystem-3col-01.c-content-about-ecosystem-3col-01--text-large .c-content-about-ecosystem-3col-01__text-note {
        font-size: var(--px18);
    }
}

@media screen and (max-width: 768px) {
    .post {
        .l-about {
            padding: var(--px60) 0;
        }

        .l-about .c-container {
            width: min(calc(100% - 24px), var(--content-max-width));
        }

        .c-content-about-ecosystem-3col-01 {
            padding: var(--px60) var(--px24);
        }

        .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__title {
            font-size: var(--px60);
        }

        .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__grid-top,
        .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__grid-bottom {
            grid-template-columns: 1fr;
            gap: var(--px24);
        }

        .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__col-media-a,
        .c-content-about-ecosystem-3col-01 .c-content-about-ecosystem-3col-01__col-note {
            padding-top: 0;
        }
    }
}

.post {
    .l-about {
        width: 100%;
        overflow: hidden;
    }

    .c-content-about-collage-01 {
        position: relative;
        display: flex;
        align-items: center;
        gap: var(--px60);
        padding: var(--px80) var(--px60);
        overflow: hidden;
        background-color: var(--color-background);
    }

    .c-content-about-collage-01 h2,
    .c-content-about-collage-01 p,
    .c-content-about-collage-01 figure {
        margin: 0;
        padding: 0;
    }

    .c-content-about-collage-01 a {
        color: inherit;
        text-decoration: none;
    }

    .c-content-about-collage-01 .c-content-about-collage-01__media {
        position: relative;
        flex: 1 1 52%;
        min-width: 0;
        padding-bottom: var(--px60);
        z-index: 1;
    }

    .c-content-about-collage-01 .c-content-about-collage-01__figure {
        overflow: hidden;
        background-color: var(--color-secondary-tint);
        box-shadow: 0 16px 34px rgba(17, 17, 17, 0.12);
    }

    .c-content-about-collage-01 .c-content-about-collage-01__figure--primary {
        width: min(100%, 680px);
        aspect-ratio: 4 / 3;
    }

    .c-content-about-collage-01 .c-content-about-collage-01__figure--secondary {
        position: absolute;
        right: 0;
        bottom: 0;
        width: min(44%, 280px);
        aspect-ratio: 3 / 4;
        border: 4px solid var(--color-background);
        z-index: 2;
    }

    .c-content-about-collage-01 .c-content-about-collage-01__image {
        display: block;
        width: 100% !important;
        height: 100% !important;
        max-width: none !important;
        max-height: none !important;
        object-fit: cover;
    }

    .c-content-about-collage-01 .c-content-about-collage-01__body {
        position: relative;
        flex: 1 1 48%;
        display: flex;
        flex-direction: column;
        align-items: flex-start;
        gap: var(--px24);
        z-index: 1;
    }

    .c-content-about-collage-01 .c-content-about-collage-01__eyebrow {
        color: var(--color-primary);
        font-family: var(--font-family02);
        font-size: var(--px60);
        font-weight: 700;
        letter-spacing: 0.06em;
        line-height: 1;
    }

    .c-content-about-collage-01 .c-content-about-collage-01__title {
        color: var(--color-primary-shade);
        font-size: var(--px30);
        font-weight: 700;
        line-height: 1.5;
    }

    .c-content-about-collage-01 .c-content-about-collage-01__title--underline {
        padding-bottom: var(--px20);
    }

    .c-content-about-collage-01 .c-content-about-collage-01__title--underline::after {
        content: "";
        display: block;
        width: 74px;
        height: 2px;
        margin-top: 14px;
        background-color: var(--color-primary);
    }

    .c-content-about-collage-01 .c-content-about-collage-01__lead {
        color: var(--color-primary);
        font-size: var(--px16);
        line-height: 1.95;
    }

    .c-content-about-collage-01 .c-content-about-collage-01__button {
        display: inline-flex;
        justify-content: center;
        align-items: center;
        min-width: var(--px240);
        padding: 16px 28px;
        background-color: var(--color-primary-shade);
        color: var(--color-background);
        font-size: var(--px14);
        font-weight: 700;
        line-height: 1;
        transition: opacity 0.2s ease;
    }

    .c-content-about-collage-01 .c-content-about-collage-01__button:hover {
        opacity: 0.82;
    }

    .c-content-about-collage-01 .c-content-about-collage-01__decor {
        position: absolute;
        right: 0;
        bottom: 0;
        left: 0;
        height: var(--px160);
        background-image: radial-gradient(circle, var(--color-secondary) 1px, transparent 1px);
        background-size: 8px 8px;
        opacity: 0.32;
        pointer-events: none;
    }

    .c-content-about-collage-01.c-content-about-collage-01--bg-gray {
        background-color: var(--color-secondary-tint);
    }

    .c-content-about-collage-01.c-content-about-collage-01--full-width {
        width: 100vw;
        margin-right: calc(50% - 50vw);
        margin-left: calc(50% - 50vw);
    }

    .c-content-about-collage-01.c-content-about-collage-01--reverse {
        flex-direction: row-reverse;
    }

    .c-content-about-collage-01.c-content-about-collage-01--reverse .c-content-about-collage-01__figure--secondary {
        right: auto;
        left: 0;
    }
}

@media screen and (max-width: 768px) {
    .post {
        .l-about {
            padding: var(--px60) 0;
        }

        .l-about .c-container {
            width: min(calc(100% - 24px), var(--content-max-width));
        }

        .c-content-about-collage-01 {
            flex-direction: column;
            gap: var(--px40);
            padding: var(--px60) var(--px24);
        }

        .c-content-about-collage-01 .c-content-about-collage-01__media {
            width: 100%;
            padding-bottom: var(--px40);
        }

        .c-content-about-collage-01 .c-content-about-collage-01__figure--primary {
            width: 100%;
        }

        .c-content-about-collage-01 .c-content-about-collage-01__figure--secondary {
            width: min(46%, 220px);
        }

        .c-content-about-collage-01 .c-content-about-collage-01__body {
            width: 100%;
        }

        .c-content-about-collage-01 .c-content-about-collage-01__eyebrow {
            font-size: var(--px40);
        }

        .c-content-about-collage-01 .c-content-about-collage-01__title {
            font-size: var(--px24);
        }

        .c-content-about-collage-01 .c-content-about-collage-01__button {
            width: 100%;
            min-width: 0;
        }

        .c-content-about-collage-01.c-content-about-collage-01--reverse {
            flex-direction: column;
        }

        .c-content-about-collage-01.c-content-about-collage-01--reverse .c-content-about-collage-01__figure--secondary {
            right: 0;
            left: auto;
        }
    }
}

.post {
    .l-faq {
        width: 100%;
        padding: var(--px80) 0;
    }

    .l-faq .c-container {
        width: min(calc(100% - 40px), var(--content-max-width));
        margin-right: auto;
        margin-left: auto;
    }

    .l-faq.l-faq--bg-gray {
        background-color: var(--color-secondary-tint);
    }

    .c-support-faq-accordion-01 {
        max-width: 960px;
        margin-right: auto;
        margin-left: auto;
    }

    .c-support-faq-accordion-01 h2,
    .c-support-faq-accordion-01 p,
    .c-support-faq-accordion-01 ul,
    .c-support-faq-accordion-01 li,
    .c-support-faq-accordion-01 details,
    .c-support-faq-accordion-01 summary {
        margin: 0;
        padding: 0;
    }

    .c-support-faq-accordion-01 .c-support-faq-accordion-01__list {
        list-style: none;
    }

    .c-support-faq-accordion-01 .c-support-faq-accordion-01__header {
        margin-bottom: var(--px40);
        text-align: center;
    }

    .c-support-faq-accordion-01 .c-support-faq-accordion-01__eyebrow {
        color: var(--color-primary);
        font-family: var(--font-family02);
        font-size: var(--px14);
        font-weight: 700;
        letter-spacing: 0.12em;
        line-height: 1.4;
        text-transform: uppercase;
    }

    .c-support-faq-accordion-01 .c-support-faq-accordion-01__title {
        margin-top: 8px;
        color: var(--color-primary-shade);
        font-size: var(--px30);
        font-weight: 700;
        line-height: 1.3;
    }

    .c-support-faq-accordion-01 .c-support-faq-accordion-01__item {
        border-bottom: 1px solid var(--color-table-border);
    }

    .c-support-faq-accordion-01 .c-support-faq-accordion-01__item:first-child {
        border-top: 1px solid var(--color-table-border);
    }

    .c-support-faq-accordion-01 .c-support-faq-accordion-01__question {
        position: relative;
        display: flex;
        align-items: center;
        gap: var(--px16);
        padding: var(--px24) 48px var(--px24) 0;
        cursor: pointer;
        list-style: none;
    }

    .c-support-faq-accordion-01 .c-support-faq-accordion-01__question::-webkit-details-marker {
        display: none;
    }

    .c-support-faq-accordion-01 .c-support-faq-accordion-01__question::after {
        content: "";
        position: absolute;
        top: 50%;
        right: 8px;
        width: 10px;
        height: 10px;
        border-right: 2px solid var(--color-primary);
        border-bottom: 2px solid var(--color-primary);
        transform: translateY(-70%) rotate(45deg);
        transition: transform 0.2s ease;
    }

    .c-support-faq-accordion-01 .c-support-faq-accordion-01__detail[open] .c-support-faq-accordion-01__question::after {
        transform: translateY(-30%) rotate(-135deg);
    }

    .c-support-faq-accordion-01 .c-support-faq-accordion-01__q-icon,
    .c-support-faq-accordion-01 .c-support-faq-accordion-01__a-icon {
        flex-shrink: 0;
        display: inline-flex;
        align-items: center;
        justify-content: center;
        width: 32px;
        height: 32px;
        font-size: var(--px14);
        font-weight: 700;
        border-radius: 4px;
    }

    .c-support-faq-accordion-01 .c-support-faq-accordion-01__q-icon {
        background-color: var(--color-primary);
        color: var(--color-background);
    }

    .c-support-faq-accordion-01 .c-support-faq-accordion-01__a-icon {
        border: 1px solid var(--color-table-border);
        background-color: var(--color-secondary-tint);
        color: var(--color-primary);
    }

    .c-support-faq-accordion-01 .c-support-faq-accordion-01__question-text {
        flex: 1 1 auto;
        color: var(--color-primary-shade);
        font-size: var(--px16);
        font-weight: 700;
        line-height: 1.6;
    }

    .c-support-faq-accordion-01 .c-support-faq-accordion-01__answer {
        display: flex;
        align-items: flex-start;
        gap: var(--px16);
        padding: 0 48px var(--px24) 0;
    }

    .c-support-faq-accordion-01 .c-support-faq-accordion-01__answer-text {
        flex: 1 1 auto;
        color: var(--color-primary);
        font-size: var(--px16);
        line-height: 1.85;
    }
}

@media screen and (max-width: 768px) {
    .post {
        .l-faq {
            padding: var(--px60) 0;
        }

        .l-faq .c-container {
            width: min(calc(100% - 24px), var(--content-max-width));
        }

        .c-support-faq-accordion-01 .c-support-faq-accordion-01__question,
        .c-support-faq-accordion-01 .c-support-faq-accordion-01__answer {
            gap: 12px;
            padding-right: 36px;
        }
    }
}

.post {
    .l-card-list {
        width: 100%;
        padding: var(--px80) 0;
    }

    .l-card-list .c-container {
        width: min(calc(100% - 40px), var(--content-max-width));
        margin-right: auto;
        margin-left: auto;
    }

    .l-card-list.l-card-list--bg-gray {
        background-color: var(--color-secondary-tint);
    }

    .c-list-card-grid-01 h3,
    .c-list-card-grid-01 p,
    .c-list-card-grid-01 ul,
    .c-list-card-grid-01 li,
    .c-list-card-grid-01 figure {
        margin: 0;
        padding: 0;
    }

    .c-list-card-grid-01 .c-list-card-grid-01__list {
        display: grid;
        grid-template-columns: 1fr;
        gap: var(--px24);
        list-style: none;
    }

    .c-list-card-grid-01 .c-list-card-grid-01__list--col-2 {
        grid-template-columns: repeat(2, minmax(0, 1fr));
    }

    .c-list-card-grid-01 .c-list-card-grid-01__list--col-3 {
        grid-template-columns: repeat(3, minmax(0, 1fr));
    }

    .c-list-card-grid-01 .c-list-card-grid-01__list--col-4 {
        grid-template-columns: repeat(4, minmax(0, 1fr));
    }

    .c-list-card-grid-01 .c-list-card-grid-01__item {
        display: flex;
        flex-direction: column;
        overflow: hidden;
    }

    .c-list-card-grid-01 .c-list-card-grid-01__media {
        overflow: hidden;
        aspect-ratio: 3 / 2;
        background-color: var(--color-secondary-tint);
    }

    .c-list-card-grid-01 .c-list-card-grid-01__image {
        display: block;
        width: 100% !important;
        height: 100% !important;
        max-width: none !important;
        max-height: none !important;
        object-fit: cover;
        transition: transform 0.3s ease;
    }

    .c-list-card-grid-01 .c-list-card-grid-01__item:hover .c-list-card-grid-01__image {
        transform: scale(1.04);
    }

    .c-list-card-grid-01 .c-list-card-grid-01__body {
        display: flex;
        flex: 1 1 auto;
        flex-direction: column;
        gap: 12px;
        padding-top: var(--px16);
    }

    .c-list-card-grid-01 .c-list-card-grid-01__title {
        color: var(--color-primary-shade);
        font-size: var(--px18);
        font-weight: 700;
        line-height: 1.5;
    }

    .c-list-card-grid-01 .c-list-card-grid-01__text {
        color: var(--color-primary);
        font-size: var(--px16);
        line-height: 1.85;
    }

    .c-list-card-grid-01 .c-list-card-grid-01__item--card {
        background-color: var(--color-background);
        box-shadow: 0 2px 12px rgba(17, 17, 17, 0.08);
    }

    .c-list-card-grid-01 .c-list-card-grid-01__item--card .c-list-card-grid-01__body {
        padding: var(--px24);
    }

    .c-list-card-grid-01 .c-list-card-grid-01__item--bordered {
        background-color: var(--color-background);
        border: 1px solid var(--color-table-border);
    }

    .c-list-card-grid-01 .c-list-card-grid-01__item--bordered .c-list-card-grid-01__body {
        padding: var(--px24);
    }

    .c-list-card-grid-01 .c-list-card-grid-01__item--padded {
        padding: var(--px24);
        background-color: var(--color-background);
        box-shadow: 0 2px 12px rgba(17, 17, 17, 0.08);
    }

    .c-list-card-grid-01 .c-list-card-grid-01__item--padded .c-list-card-grid-01__body {
        padding: 0;
    }
}

@media screen and (max-width: 768px) {
    .post {
        .l-card-list {
            padding: var(--px60) 0;
        }

        .l-card-list .c-container {
            width: min(calc(100% - 24px), var(--content-max-width));
        }

        .c-list-card-grid-01 .c-list-card-grid-01__list,
        .c-list-card-grid-01 .c-list-card-grid-01__list--col-2,
        .c-list-card-grid-01 .c-list-card-grid-01__list--col-3,
        .c-list-card-grid-01 .c-list-card-grid-01__list--col-4 {
            grid-template-columns: 1fr;
        }
    }
}

.post {
    .l-company {
        width: 100%;
        padding: var(--px80) 0;
    }

    .l-company .c-container {
        width: min(calc(100% - 40px), var(--content-max-width));
        margin-right: auto;
        margin-left: auto;
    }

    .l-company.l-company--bg-gray {
        background-color: var(--color-secondary-tint);
    }

    .c-info-company-table-01 {
        max-width: 960px;
        margin-right: auto;
        margin-left: auto;
    }

    .c-info-company-table-01 h2,
    .c-info-company-table-01 p,
    .c-info-company-table-01 table,
    .c-info-company-table-01 tbody,
    .c-info-company-table-01 tr,
    .c-info-company-table-01 th,
    .c-info-company-table-01 td {
        margin: 0;
        padding: 0;
    }

    .c-info-company-table-01 .c-info-company-table-01__header {
        margin-bottom: var(--px40);
        text-align: center;
    }

    .c-info-company-table-01 .c-info-company-table-01__eyebrow {
        color: var(--color-primary);
        font-family: var(--font-family02);
        font-size: var(--px14);
